// UTM Simulation Algorithm
// Input: <M, w> where M = (Q, Σ, Γ, δ, q0, B, F) and w = input

BEGIN
// Step 1: Parse description of M and input w
READ input tape
DECODE transition function δ of M
LOCATE w on simulation area of tape

// Step 2: Main simulation loop
REPEAT
 // Read current state and symbol
 current_state ← READ_STATE()
 current_symbol ← READ_TAPE()

 // Look up transition in δ
 IF δ(current_state, current_symbol) = (new_state, write_symbol, direction) THEN
 // Write new symbol
 WRITE_TAPE(write_symbol)

 // Update state
 WRITE_STATE(new_state)

 // Move head
 IF direction = 'L' THEN MOVE_LEFT()
 IF direction = 'R' THEN MOVE_RIGHT()

 // Check for halting
 IF new_state IN F THEN
 ACCEPT and HALT
 END IF
 ELSE
 // No transition defined - reject
 REJECT and HALT
 END IF
UNTIL FALSE

END

// This is a CONCEPTUAL illustration - such machine CANNOT exist
// Purpose: To understand the undecidability proof

BEGIN
// Proposed Halting Decider H(p, w)
FUNCTION H(p, w):
 // Input: Program p and input w
 // Output: 'YES' if p halts on w, 'NO' if p loops on w

 // THEORETICAL: Simulate p on w
 SIMULATE(p, w)

 IF simulation_halts THEN
 RETURN 'YES'
 ELSE
 RETURN 'NO'

// Now construct D that creates paradox
FUNCTION D(M):
 // Input: Description of machine M

 result ← H(M, M) // Ask if M halts on its own description

 IF result = 'YES' THEN
 // If H says M halts, D enters infinite loop
 WHILE TRUE DO
 // Loop forever
 END WHILE
 ELSE
 // If H says M loops, D halts
 RETURN

// Now run D on itself
D(D)

// Analysis:
// - If H says D halts → D loops forever (contradiction)
// - If H says D loops → D halts (contradiction)
// Therefore H cannot exist!

END
